const item = $input.first();
const json = item?.json ?? {};
const binary = item?.binary ?? {};
const archive = binary.reviewZip ?? binary.archive ?? null;
const staticData = $getWorkflowStaticData('global');
if (!staticData.reviewZips) staticData.reviewZips = {};

const now = Date.now();
for (const [key, value] of Object.entries(staticData.reviewZips)) {
  if (!value || typeof value !== 'object' || !value.createdAt || now - value.createdAt > 24 * 60 * 60 * 1000) {
    delete staticData.reviewZips[key];
  }
}

const archiveData = String(archive?.data ?? json.archiveData ?? '').trim();
const archiveId = String(archive?.id ?? '').trim();
if (!archiveData) throw new Error('archiveData is required');
if (archiveData === 'filesystem-v2' && !archiveId) {
  throw new Error('archiveId is required for filesystem-backed binary data');
}

const token = 'api_draft_' + now + '_' + Math.random().toString(36).slice(2, 10);
const storedArchive = {
  data: archiveData,
  id: archiveId,
  mimeType: String(archive?.mimeType ?? json.archiveMimeType ?? 'application/zip') || 'application/zip',
  fileName: String(archive?.fileName ?? json.archiveFileName ?? 'api.zip') || 'api.zip',
  fileExtension: String(archive?.fileExtension ?? 'zip') || 'zip',
  fileSize: String(archive?.fileSize ?? ''),
  bytes: Number(archive?.bytes ?? 0) || undefined,
  createdAt: now,
  token,
};

staticData.reviewZips[token] = storedArchive;
staticData.latestReviewZipToken = token;

return [{
  json: {
    response: String(json.response ?? ''),
    revisionNumber: Number(json.revisionNumber ?? 0) || 0,
    zipDownloadToken: token,
    zipDownloadUrl: '/webhook/review-download-file',
  }
}];

const item = $input.first()?.json ?? {};
const token = String(item.query?.token ?? '').trim();
const staticData = $getWorkflowStaticData('global');
const reviewZips = staticData.reviewZips || {};
let resolvedToken = token || String(staticData.latestReviewZipToken ?? '').trim();
let stored = resolvedToken ? reviewZips[resolvedToken] : null;

if (!stored) {
  for (const [candidateToken, candidate] of Object.entries(reviewZips)) {
    if (!candidate || typeof candidate !== 'object' || !candidate.data) continue;
    if (!stored || Number(candidate.createdAt ?? 0) > Number(stored.createdAt ?? 0)) {
      stored = candidate;
      resolvedToken = candidateToken;
    }
  }
}

if (!stored?.data) throw new Error('Review ZIP not found or expired');

const archive = {
  data: stored.data,
  mimeType: stored.mimeType || 'application/zip',
  fileName: stored.fileName,
  fileExtension: stored.fileExtension || 'zip',
};
if (stored.id) archive.id = stored.id;

return [{ json: { token: resolvedToken || stored.token || '' }, binary: { archive } }];
